// Parse the CSV and compute every number deterministically in code.
// The AI node downstream only turns THESE numbers into prose; it never does math.
const raw = $input.first().json.data || $input.first().json.body || "";
const lines = String(raw).trim().split(/\r?\n/).filter((l) => l.length > 0);
if (lines.length < 2) {
  throw new Error("CSV had no data rows. Check the sheet URL / sharing.");
}

const strip = (s) => s.trim().replace(/^"(.*)"$/, "$1");
const header = lines[0].split(",").map(strip);
const idx = (name) => header.indexOf(name);
const col = {
  product: idx("product_name"),
  sold: idx("units_sold_yesterday"),
  price: idx("unit_price"),
  cost: idx("unit_cost"),
  stock: idx("stock_level"),
  reorder: idx("reorder_point"),
};
for (const [k, v] of Object.entries(col)) {
  if (v === -1) throw new Error(`CSV is missing the '${k}' column.`);
}

const num = (v) => {
  const n = Number(String(v).replace(/[^0-9.\-]/g, ""));
  return Number.isFinite(n) ? n : 0;
};

const products = lines.slice(1).map((line) => {
  const c = line.split(",").map(strip);
  const price = num(c[col.price]);
  const cost = num(c[col.cost]);
  const sold = num(c[col.sold]);
  const stock = num(c[col.stock]);
  const reorder = num(c[col.reorder]);
  const revenue = +(sold * price).toFixed(2);
  const margin = price > 0 ? (price - cost) / price : 0;
  return {
    product_name: c[col.product],
    units_sold_yesterday: sold,
    unit_price: price,
    unit_cost: cost,
    stock_level: stock,
    reorder_point: reorder,
    revenue,
    margin,
  };
});

const totalRevenue = +products.reduce((s, p) => s + p.revenue, 0).toFixed(2);
const totalUnits = products.reduce((s, p) => s + p.units_sold_yesterday, 0);
const top3 = [...products].sort((a, b) => b.revenue - a.revenue).slice(0, 3);
const lowStock = products.filter((p) => p.stock_level < p.reorder_point);
const lowMargin = products.filter((p) => p.margin < 0.25);

const money = (n) => "$" + n.toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 });
const pct = (n) => (n * 100).toFixed(1) + "%";

const prompt =
  "You are an operations analyst. Write a short, plain-English daily ops brief " +
  "(4-6 sentences, no bullet lists, no preamble) using ONLY these already-computed numbers. " +
  "Do not invent figures.\n\n" +
  `Date: yesterday\n` +
  `Total revenue: ${money(totalRevenue)}\n` +
  `Total units sold: ${totalUnits}\n` +
  `Top sellers: ${top3.map((p) => `${p.product_name} (${money(p.revenue)})`).join(", ")}\n` +
  `Low stock (${lowStock.length}): ${lowStock.map((p) => `${p.product_name} ${p.stock_level}/${p.reorder_point}`).join(", ") || "none"}\n` +
  `Low margin (<25%) (${lowMargin.length}): ${lowMargin.map((p) => `${p.product_name} ${pct(p.margin)}`).join(", ") || "none"}\n`;

const anthropicPayload = {
  model: "claude-sonnet-5",
  max_tokens: 400,
  messages: [{ role: "user", content: prompt }],
};

const headerLine =
  `:bar_chart: *Daily Ops Brief* — Revenue ${money(totalRevenue)} | ${totalUnits} units | ` +
  `${lowStock.length} low-stock | ${lowMargin.length} low-margin`;

return [{
  json: {
    totalRevenue,
    totalUnits,
    top3,
    low_stock: lowStock,
    low_margin: lowMargin,
    prompt,
    anthropicPayload,
    headerLine,
  },
}];

// Pull Claude's prose out of the API response and prepend the hard numbers,
// which we read back from the Compute node so they survive the HTTP round-trip.
const metrics = $('Compute Metrics & Flags').first().json;
const resp = $input.first().json;
let claudeText = "";
if (resp && Array.isArray(resp.content) && resp.content[0] && resp.content[0].text) {
  claudeText = resp.content[0].text.trim();
} else {
  claudeText = "(AI brief unavailable; numbers below are authoritative.)";
}
const slackText = `${metrics.headerLine}\n\n${claudeText}`;
return [{ json: { slackText } }];

// Emit ONE ITEM PER low-stock product. If the list is empty this returns [],
// so the Cadence HTTP node simply never runs — no IF node needed.
const metrics = $('Compute Metrics & Flags').first().json;
const lowStock = metrics.low_stock || [];
const tomorrow = new Date(Date.now() + 86400000).toISOString().slice(0, 10);
const slug = (s) => String(s).toLowerCase().trim().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "");

return lowStock.map((p) => ({
  json: {
    body: {
      title: `Restock: ${p.product_name}`,
      due_date: tomorrow,
      notes: `Stock ${p.stock_level} is at or below reorder point ${p.reorder_point}.`,
      source_key: `restock:${slug(p.product_name)}`,
    },
  },
}));
